export default function CategoryFilter({ examples }: Props) {
  const [active, setActive] = useState<"all" | ExampleCategory>("all");

  const filtered =
    active === "all" ? examples : examples.filter(e => e.category === active);

  return (
    <div>
      <div className="mb-8 flex flex-wrap gap-2">
        {categories.map(cat => (
          <button
            key={cat}
            onClick={() => setActive(cat)}
            className={`rounded-md px-3 py-1.5 font-mono text-xs tracking-wider transition-colors ${
              active === cat
                ? "bg-accent text-zinc-950"
                : "bg-zinc-800/50 text-zinc-400 hover:text-zinc-100"
            }`}>
            {labels[cat]}
            {cat !== "all" && (
              <span className="ml-1.5 text-[10px] opacity-60">
                {examples.filter(e => e.category === cat).length}
              </span>
            )}
          </button>
        ))}
      </div>

      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
        {filtered.map(example => (
          <a
            key={example.slug}
            href={`/examples/${example.slug}`}
            data-astro-prefetch="viewport"
            className="group flex flex-col rounded-lg border border-zinc-800 bg-zinc-900/50 p-5 transition-colors hover:border-emerald-500/40">
            <div className="mb-2 font-mono text-[10px] uppercase tracking-widest text-zinc-500">
              {labels[example.category]}
            </div>
            <h3 className="mb-1 font-display text-base italic text-zinc-100 group-hover:text-emerald-400 transition-colors">
              {example.title}
            </h3>
            <p className="text-sm leading-[1.75] text-zinc-400 flex-1">
              {example.description}
            </p>
            {example.icons && example.icons.length > 0 && (
              <div className="mt-3 flex items-center gap-1.5 text-zinc-600">
                {example.icons.map(icon => (
                  <TechIcon key={icon} name={icon} />
                ))}
              </div>
            )}
          </a>
        ))}
      </div>

      {filtered.length === 0 && (
        <p className="py-12 text-center text-zinc-500">
          No examples in this category yet.
        </p>
      )}
    </div>
  );
}
